+    let temp_root = unique_temp_dir("pgo-fallback");
+    let bin_dir = temp_root.join("bin");
+    let target_dir = temp_root.join("target");
+    let out_dir = temp_root.join("out");
+    let profile_dir = temp_root.join("profiles");
